<?php use App\Helpers\Csrf; use App\Helpers\Sanitizer; use App\Helpers\Url; ?>
<main class="container"><section class="module-hero"><div><span class="eyebrow">Ubicación física</span><h1>Secciones</h1><p>Organiza dónde se encuentra cada pieza dentro del rastro para facilitar búsquedas internas.</p></div><div class="action-row"><a class="btn btn-secundario" href="<?= Sanitizer::html(Url::ruta('/dashboard')) ?>">Panel</a><a class="btn" href="<?= Sanitizer::html(Url::ruta('/secciones/crear')) ?>">Nueva sección</a></div></section><section class="card"><form class="filter-form" method="GET"><div class="form-group"><label>Buscar</label><input name="buscar" value="<?= Sanitizer::html($busqueda ?? '') ?>" placeholder="Código o nombre"></div><div class="form-group"><label>Estado</label><select name="estado"><option value="">Todos</option><option value="1" <?= ($estado ?? '')==='1'?'selected':'' ?>>Activas</option><option value="0" <?= ($estado ?? '')==='0'?'selected':'' ?>>Inactivas</option></select></div><div class="form-actions compact"><button class="btn">Filtrar</button><a class="btn btn-secundario" href="<?= Sanitizer::html(Url::ruta('/secciones')) ?>">Limpiar</a></div></form></section><section class="card table-wrapper"><table><thead><tr><th>Código</th><th>Nombre</th><th>Descripción</th><th>Estado</th><th>Acciones</th></tr></thead><tbody><?php if(empty($secciones)): ?><tr><td colspan="5" class="empty-state">No hay secciones registradas.</td></tr><?php endif; ?><?php foreach($secciones as $seccion): ?><tr><td><span class="chip"><?= Sanitizer::html($seccion['codigo']) ?></span></td><td><?= Sanitizer::html($seccion['nombre_seccion']) ?></td><td><?= Sanitizer::html($seccion['descripcion'] ?? '') ?></td><td><?= (int)$seccion['activo']===1?'<span class="badge badge-success">Activa</span>':'<span class="badge badge-danger">Inactiva</span>' ?></td><td class="acciones-tabla"><a class="btn btn-mini btn-secundario" href="<?= Sanitizer::html(Url::ruta('/secciones/editar/'.$seccion['id_seccion'])) ?>">Editar</a><form method="POST" action="<?= Sanitizer::html(Url::ruta('/secciones/estado/'.$seccion['id_seccion'])) ?>" data-confirm="¿Cambiar estado de la sección?"><?= Csrf::campo() ?><input type="hidden" name="activo" value="<?= (int)$seccion['activo']===1?0:1 ?>"><button class="btn btn-mini <?= (int)$seccion['activo']===1?'btn-danger':'' ?>" type="submit"><?= (int)$seccion['activo']===1?'Desactivar':'Activar' ?></button></form></td></tr><?php endforeach; ?></tbody></table></section></main>
